svg.script:
(function() {
  const svgRoot = document.getElementById('champy-svg-root');
  const timelineCursor = document.getElementById('timeline-cursor');
  const playPauseIcon = document.getElementById('play-pause-icon');
  const TOTAL_SCENES = 7;
  const SCENE_DURATION_MS = 8000;
  const TIMELINE_POSITIONS = [171, 314, 457, 600, 743, 886, 1029];

  let currentScene = 1;
  let isPlaying = true;
  let autoTimer = null;

  function applyScene(n) {
    for (let i = 1; i <= TOTAL_SCENES; i++) {
      svgRoot.classList.remove('scene-' + i + '-active');
    }
    svgRoot.classList.add('scene-' + n + '-active');
    currentScene = n;
    if (timelineCursor) {
      timelineCursor.setAttribute('cx', TIMELINE_POSITIONS[n - 1]);
    }
    // Note : l'anneau CSS reset tout seul en infinite, pas besoin de toucher ici.
    // Resync uniquement sur action utilisateur (cf. userJump).
  }

  function startAuto() {
    if (autoTimer) return;
    autoTimer = setInterval(function() {
      const next = currentScene === TOTAL_SCENES ? 1 : currentScene + 1;
      applyScene(next);
    }, SCENE_DURATION_MS);
    isPlaying = true;
  }

  function stopAuto() {
    if (autoTimer) {
      clearInterval(autoTimer);
      autoTimer = null;
    }
    isPlaying = false;
  }


  function userJump(n) {
    // Action utilisateur : changement de scene + reset visuel + arret auto
    applyScene(n);
    resetProgressRing();
    stopAuto();
  }


  // ==========================================================
  // Attache des event listeners au chargement.
  // Robuste a la CSP de Streamlit qui peut bloquer les onclick
  // inline dans une iframe components.html.
  // ==========================================================
  function attachListeners() {
    // Event delegation : listener sur DOCUMENT plutot que svgRoot.
    // Si l'iframe Streamlit relaie les clics au document HTML englobant,
    // on les attrape la. Sinon, les clics SVG remonteront jusqu'a document
    // par bubbling.

    // Tracker debug : tout clic detecte met l'indicateur en bleu.
    // Permet de savoir si les clics arrivent ou si le dispatch foire.
    // Helper : remontee manuelle du DOM pour trouver un parent avec data-action.
    // Robuste sur SVG (closest() peut buguer) avec try/catch et parentElement fallback.
    function findActionAncestor(node) {
      let safety = 0;
      while (node && safety < 20) {
        safety++;
        try {
          if (node.getAttribute && node.getAttribute('data-action')) {
            return node;
          }
        } catch (e) {}
        node = node.parentNode || node.parentElement;
      }
      return null;
    }

    document.addEventListener('click', function(e) {

      try {
        const t = e.target;
        tagInfo = (t.tagName || 'unk').toLowerCase();
        const cls = t.getAttribute && t.getAttribute('class');
        if (cls) tagInfo += '.' + cls.split(' ')[0];
        const act = t.getAttribute && t.getAttribute('data-action');
        if (act) tagInfo += '@' + act;
      } catch (err) { tagInfo = 'err'; }

      const el = findActionAncestor(e.target);
      if (!el) return;
      const action = el.getAttribute('data-action');
      // Si action trouvee : indicateur vert
      switch (action) {
        case 'prev':
          userJump(currentScene === 1 ? TOTAL_SCENES : currentScene - 1);
          break;
        case 'next':
          userJump(currentScene === TOTAL_SCENES ? 1 : currentScene + 1);
          break;
        case 'jump':
          const sceneNum = parseInt(el.getAttribute('data-scene'), 10);
          if (sceneNum >= 1 && sceneNum <= TOTAL_SCENES) userJump(sceneNum);
          break;
      }
    }, true);  // capture phase : on attrape avant que d'autres listeners interceptent
  }

  // Init : attache les listeners, puis demarre en scene 1 mode auto
  try {
    setTimeout(attachListeners, 100);
  } catch (e) {}
  applyScene(1);
  startAuto();
})();
